/**
 * 양력 날짜를 음력으로 변환
 * @param {number} year - 양력 연도
 * @param {number} month - 양력 월 (1~12)
 * @param {number} day - 양력 일
 * @returns {{year:number, month:number, day:number, isLeap:boolean}|null}
 */
function solarToLunarDate(year, month, day) {
  const key = String(year).padStart(4,'0') + String(month).padStart(2,'0') + String(day).padStart(2,'0');
  const v = solarToLunar[key];
  if (!v) return null;
  return { year: v.y, month: v.m, day: v.d, isLeap: v.leap };
}

/**
 * 음력 날짜를 양력으로 변환
 * @param {number} year - 음력 연도
 * @param {number} month - 음력 월 (1~12)
 * @param {number} day - 음력 일
 * @param {boolean} isLeap - 윤달 여부 (기본값: false)
 * @returns {{year:number, month:number, day:number}|null}
 */
function lunarToSolarDate(year, month, day, isLeap = false) {
  let key = String(year).padStart(4,'0') + String(month).padStart(2,'0') + String(day).padStart(2,'0');
  if (isLeap) key += '_leap';
  const v = lunarToSolar[key];
  if (!v) return null;
  return {
    year: parseInt(v.slice(0,4)),
    month: parseInt(v.slice(4,6)),
    day: parseInt(v.slice(6,8))
  };
}

if (typeof module !== 'undefined') {
  module.exports = { solarToLunar, lunarToSolar, solarToLunarDate, lunarToSolarDate };
}
